<template>
  <div class="cus-distributor-list">
    <el-card>
      <SpFinder
        ref="finder"
        :noSelection='true'
        :hooks="{
          beforeSearch: beforeSearch
        }"
        :setting="setting"
        url="/adapay/dealer/distributors"
        @reset="onFinderReset"
      >
        <template v-slot:address>
          <el-cascader
            v-model="checkedRegions"
            clearable
            style="width: 100%"
            :props="{ checkStrictly: true }"
            :options="regions"
            filterable
            @change="handleRegionChange"
          />
        </template>
      </SpFinder>
    </el-card>
  </div>
</template>

<script>
import district from "@/common/district.json"
import { createSetting } from '@shopex/finder'

// 取選中地區的值
function getCascaderObj (val, opt) {
  return val && val.map(function (value, index, array) {
    for (var itm of opt) {
      if (itm.value === value) {
        opt = itm.children
        return itm
      }
    }
    return null
  })
}
export default {
  data () {
    return {
      province: '',
      city: '',
      area: '',
      regions: district,
      checkedRegions: [],
      statusList: [
        { label: '未入網', value: 1 },
        { label: '待審核', value: 2 },
        { label: '入網成功', value: 3 }
      ],
    }
  },
  computed: {
    setting () {
      return createSetting({
        columns: [
          { name: '店鋪名稱', key: 'name'  },
          { name: '負責人', key: 'contact' },
          { name: '聯絡方式', key: 'mobile' },
          { name: '經營地址', key: 'address' },
          { name: '狀態', key: '', formatter: (h, { audit_state }) => (audit_state == '1' && '未入網') || (audit_state == '2' && '待審核') || (audit_state == '3' && '入網成功') }
        ],
        search: [
          { type: 'input', key: 'name', name: '店鋪名稱', placeholder: '請輸入店鋪名稱' },
          { type: 'input', key: 'contact', name: '負責人', placeholder: '請輸入負責人' },
          { type: 'input', key: 'mobile', name: '聯絡方式', placeholder: '請輸入聯絡方式' },
          { key: 'address', name: '經營地址', slot: 'address' },
          { type: 'select', key: 'audit_state', options: this.statusList, name: '狀態', placeholder: '請選擇' }
        ]
      })
    }
  },
  methods: {
    beforeSearch (params) {
      params = {
        ...params,
        province: this.province,
        city: this.city,
        area: this.area
      }
      return params
    },
    handleRegionChange (value) {
      var vals = getCascaderObj(value, this.regions)
      if (vals.length == 1) {
        this.province = vals[0].label
      } else if (vals.length == 2) {
        this.province = vals[0].label
        this.city = vals[1].label
      } else if (vals.length == 3) {
        this.province = vals[0].label
        this.city = vals[1].label
        this.area = vals[2].label
      } else {
        this.province = ''
        this.city = ''
        this.area = ''
      }
    },
    // 搜尋重置
    onFinderReset () {
      this.checkedRegions = []
      this.province = ''
      this.area = ''
      this.city = ''
    }
  }
}
</script>

